package actor

import (
	"context"

	"google.golang.org/grpc"
	"google.golang.org/protobuf/types/known/emptypb"

	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/generated/protos/types/devvit/runtime"
	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/generated/protos/types/devvit/runtime/actor"
	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/grpc/proxyutil"
)

type RuntimeActorProxy struct {
	actor.UnimplementedRuntimeActorServer
	client actor.RuntimeActorClient
}

func init() {
	proxyutil.Register(&actor.RuntimeActor_ServiceDesc, NewRuntimeActorProxy)
}
func NewRuntimeActorProxy(cc grpc.ClientConnInterface) actor.RuntimeActorServer {
	return &RuntimeActorProxy{client: actor.NewRuntimeActorClient(cc)}
}
func (p *RuntimeActorProxy) NewWorker(ctx context.Context, in *runtime.LinkedBundle) (*emptypb.Empty, error) {
	return proxyutil.ProxyMethod[runtime.LinkedBundle, emptypb.Empty](p.client.NewWorker)(ctx, in)
}
func (p *RuntimeActorProxy) TerminateWorker(ctx context.Context, in *actor.WorkerQuery) (*emptypb.Empty, error) {
	return proxyutil.ProxyMethod[actor.WorkerQuery, emptypb.Empty](p.client.TerminateWorker)(ctx, in)
}
